"use client";

import { useState } from "react";

const models = ["Recruiter", "Tech Lead", "Executive"];

export default function ChatPanel() {
  const [model, setModel] = useState(models[0]);

  return (
    <aside className="border-l border-neutral-800 flex flex-col">
      <div className="p-4 border-b border-neutral-800 flex justify-between">
        <span className="font-mono text-sm">Chat</span>
        <select
          value={model}
          onChange={(e) => setModel(e.target.value)}
          className="bg-neutral-900 border border-neutral-700 rounded px-2 py-1 text-sm"
        >
          {models.map((m) => (
            <option key={m}>{m}</option>
          ))}
        </select>
      </div>

      <div className="flex-1 p-4 text-sm text-neutral-500">
        Ask me about my work from a {model} perspective.
      </div>

      <div className="p-4 border-t border-neutral-800">
        <input
          placeholder="Type a question..."
          className="w-full bg-neutral-900 border border-neutral-700 rounded px-3 py-2 text-sm"
        />
      </div>
    </aside>
  );
}
