import { Card } from "./ui/card";
import { fileContents } from "../lib/files";

export default function EditorPanel({
  activeFile,
}: {
  activeFile: string | null;
}) {
  if (!activeFile) {
    return (
      <section className="flex items-center justify-center font-mono text-sm text-neutral-600">
        Open a file to get started
      </section>
    );
  }

  return (
    <section className="p-8 font-mono text-sm">
      <Card className="bg-neutral-900 border-neutral-800 p-6 whitespace-pre-wrap">
        <div className="mb-2 text-neutral-500">{activeFile}</div>
        {fileContents[activeFile]}
      </Card>
    </section>
  );
}
